5	describe("Conway's Game of Life - nextGeneration", () => {
6	  it("should return empty array when given empty grid", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	  it("should kill a single live cell due to underpopulation (0 neighbors)", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	  it("should kill two adjacent live cells due to underpopulation (1 neighbor each)", () => {
13	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
14	  });
15	  it("should preserve a 2x2 block still life unchanged", () => {
16	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
17	    const result = nextGeneration(block);
18	    expect(result).toHaveLength(4);
