function isLive(cell: Cell, liveCells: Cell[]): boolean {
  return liveCells.some(([x, y]) => x === cell[0] && y === cell[1]);
}

function cellKey(cell: Cell): string {
  return `${cell[0]},${cell[1]}`;
}

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const survivors = liveCells.filter((cell) => survives(cell, liveCells));

  const candidates = new Map<string, Cell>();
  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const neighbor: Cell = [x + dx, y + dy];
        if (!isLive(neighbor, liveCells)) {
          candidates.set(cellKey(neighbor), neighbor);
        }
      }
    }
  }

  const births: Cell[] = [];
  for (const candidate of candidates.values()) {
    if (countLiveNeighbors(candidate, liveCells) === 3) {
      births.push(candidate);
    }
  }

  return [...survivors, ...births];
}
